/* ─── WAVEFORM ─── */
function WaveformBar({mode, width}) {
  const bars = useRef(Array.from({length: 28}, () => new Animated.Value(2))).current;
  useEffect(() => {
    const drive = mode === 'speaking' ? 22 : 8;
    const anims = bars.map((h, i) => {
      const a = Animated.loop(Animated.sequence([
        Animated.timing(h, {toValue: 2 + Math.random() * drive, duration: 110 + i * 13, easing: Easing.inOut(Easing.sin), useNativeDriver: false}),
        Animated.timing(h, {toValue: 2, duration: 110 + i * 13, easing: Easing.inOut(Easing.sin), useNativeDriver: false}),
      ]));
      a.start(); return a;
    });
    return () => anims.forEach(a => a.stop());
  }, [mode]);
  const bw = (width / bars.length) * 0.55, gap = (width / bars.length) * 0.45;
  return (
    <View style={{width, height: 48, flexDirection: 'row', alignItems: 'center'}}>
      {bars.map((h, i) => (
        <Animated.View key={i} style={{width: bw, marginHorizontal: gap / 2, height: h, backgroundColor: C.core, opacity: .8, borderRadius: 2}}/>
      ))}
    </View>
  );
}

/* ─── HOLOGRAM AVATAR ─── */
function HologramAvatar({mode}) {
  const aW = Math.min(SW * 0.72, SH * 0.42, 360);
  const aH = aW * (923 / 720);
  const floatY = useRef(new Animated.Value(0)).current;
  const auraS  = useRef(new Animated.Value(1)).current;
  const ringR  = useRef(new Animated.Value(0)).current;
  const sweepY = useRef(new Animated.Value(0)).current;
  const faceOp = useRef(new Animated.Value(0)).current;
  const gX     = useRef(new Animated.Value(0)).current;
  const gOp    = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.timing(faceOp, {toValue: 1, duration: 2000, easing: Easing.out(Easing.cubic), useNativeDriver: true}).start();
    const f = Animated.loop(Animated.sequence([
      Animated.timing(floatY, {toValue: -10, duration: 3200, easing: Easing.inOut(Easing.sin), useNativeDriver: true}),
      Animated.timing(floatY, {toValue: 0,   duration: 3200, easing: Easing.inOut(Easing.sin), useNativeDriver: true}),
    ])); f.start();
    const r = Animated.loop(Animated.timing(ringR, {toValue: 1, duration: 26000, easing: Easing.linear, useNativeDriver: true})); r.start();
    const sw = Animated.loop(Animated.sequence([
      Animated.timing(sweepY, {toValue: aH, duration: 5500, easing: Easing.inOut(Easing.quad), useNativeDriver: true}),
      Animated.delay(1800),
      Animated.timing(sweepY, {toValue: 0, duration: 0, useNativeDriver: true}),
    ])); sw.start();
    const gl = setInterval(() => {
      if (Math.random() < (mode === 'thinking' ? 0.5 : 0.12)) {
        gX.setValue((Math.random() - .5) * 8);
        Animated.sequence([
          Animated.timing(gOp, {toValue: .55, duration: 60, useNativeDriver: true}),
          Animated.timing(gOp, {toValue: 0,   duration: 150, useNativeDriver: true}),
        ]).start();
      }
    }, 800);
    return () => {f.stop(); r.stop(); sw.stop(); clearInterval(gl);};
  }, []);

  useEffect(() => {
    const spd = mode === 'listening' ? 700 : mode === 'speaking' ? 480 : 2400;
    const a = Animated.loop(Animated.sequence([
      Animated.timing(auraS, {toValue: 1.07, duration: spd, easing: Easing.inOut(Easing.sin), useNativeDriver: true}),
      Animated.timing(auraS, {toValue: 1,    duration: spd, easing: Easing.inOut(Easing.sin), useNativeDriver: true}),
    ])); a.start(); return () => a.stop();
  }, [mode]);

  const ringDeg  = ringR.interpolate({inputRange: [0, 1], outputRange: ['0deg', '360deg']});
  const auraClr  = mode === 'thinking' ? 'rgba(255,179,71,.30)' : mode === 'listening' ? 'rgba(120,255,240,.40)' : 'rgba(55,230,255,.22)';
  const faceSrc  = FACE_B64 ? {uri: `data:image/jpeg;base64,${FACE_B64}`} : null;

  return (
    <View style={{width: aW, height: aH + 50, alignItems: 'center'}}>
      <View style={{position: 'absolute', bottom: 0, width: aW * .65, height: 16, borderRadius: 30, backgroundColor: 'rgba(55,230,255,.08)'}}/>
      <Animated.View style={{transform: [{translateY: floatY}], alignItems: 'center'}}>
        <Animated.View style={{position: 'absolute', width: aW * 1.3, height: aH * 1.2, borderRadius: aW * .65, backgroundColor: auraClr, transform: [{scale: auraS}]}}/>
        <Animated.View style={{position: 'absolute', width: aW * 1.22, height: aH * 1.12, transform: [{rotate: ringDeg}]}}>
          <Svg width="100%" height="100%">
            <Circle cx="50%" cy="50%" r="48%" stroke={C.core} strokeWidth=".7" strokeDasharray="2 7" fill="none" strokeOpacity=".32"/>
            <Circle cx="50%" cy="50%" r="43%" stroke={C.core} strokeWidth=".35" strokeDasharray="14 28" fill="none" strokeOpacity=".18"/>
          </Svg>
        </Animated.View>
        <Animated.View style={{width: aW, height: aH, opacity: faceOp, overflow: 'hidden', borderRadius: aW * .08}}>
          {faceSrc && <Image source={faceSrc} style={[st.fl, {opacity: .12, left: -5}]}/>}
          {faceSrc && <Image source={faceSrc} style={[st.fl, {opacity: .97}]}/>}
          {faceSrc && <Animated.Image source={faceSrc} style={[st.fl, {opacity: gOp, transform: [{translateX: gX}]}]}/>}
          <View style={[StyleSheet.absoluteFill, {opacity: .07}]} pointerEvents="none">
            <Svg width="100%" height="100%">
              {Array.from({length: Math.ceil(aH / 5)}).map((_, i) => (
                <Line key={i} x1="0" y1={i * 5} x2="100%" y2={i * 5} stroke={C.core} strokeWidth=".8" strokeOpacity="1"/>
              ))}
            </Svg>
          </View>
          <Animated.View style={{position: 'absolute', left: 0, right: 0, height: aH * .13, transform: [{translateY: sweepY}]}} pointerEvents="none">
            <LinearGradient colors={['transparent', 'rgba(160,255,255,.18)', 'transparent']} style={{flex: 1}}/>
          </Animated.View>
          <LinearGradient colors={['rgba(2,6,9,.92)', 'transparent', 'transparent', 'rgba(2,6,9,.92)']} locations={[0, .18, .82, 1]} start={{x:0,y:0}} end={{x:0,y:1}} style={StyleSheet.absoluteFill} pointerEvents="none"/>
          <LinearGradient colors={['rgba(2,6,9,.88)', 'transparent', 'transparent', 'rgba(2,6,9,.88)']} locations={[0, .15, .85, 1]} start={{x:0,y:0}} end={{x:1,y:0}} style={StyleSheet.absoluteFill} pointerEvents="none"/>
        </Animated.View>
        {(mode === 'speaking' || mode === 'listening') && <WaveformBar mode={mode} width={aW * .82}/>}
      </Animated.View>
    </View>
  );
}

/* ─── CONTENT RESULT MODAL ─── */
function ContentModal({title, content, onClose}) {
  const copyToClipboard = () => {
    Clipboard.setString(content);
  };
  const shareContent = async () => {
    try { await Share.share({message: content, title}); } catch {}
  };
  return (
    <Modal visible={!!content} animationType="slide">
      <View style={[st.container, {padding: 16}]}>
        <StatusBar hidden/>
        <View style={{flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14}}>
          <Text style={[st.brand, {fontSize: 12, letterSpacing: 4}]}>{title}</Text>
          <TouchableOpacity onPress={onClose} style={{borderWidth: 1, borderColor: C.coreDim, borderRadius: 3, paddingHorizontal: 10, paddingVertical: 5}}>
            <Text style={{color: C.textDim, fontSize: 12}}>✕ CLOSE</Text>
          </TouchableOpacity>
        </View>
        <ScrollView style={{flex: 1, borderWidth: 1, borderColor: C.coreDim, borderRadius: 4, padding: 12}} showsVerticalScrollIndicator>
          <Text style={{color: C.text, fontSize: 14, lineHeight: 22}}>{content}</Text>
        </ScrollView>
        <View style={{flexDirection: 'row', gap: 8, marginTop: 12}}>
          <TouchableOpacity style={[st.goBtn, {flex: 1, marginTop: 0}]} onPress={copyToClipboard}>
            <Text style={[st.goTxt, {fontSize: 11}]}>📋 COPY</Text>
          </TouchableOpacity>
          <TouchableOpacity style={[st.goBtn, {flex: 1, marginTop: 0, borderColor: C.green}]} onPress={shareContent}>
            <Text style={[st.goTxt, {fontSize: 11, color: C.green}]}>↑ SHARE</Text>
          </TouchableOpacity>
        </View>
      </View>
    </Modal>
  );
}

